 1→import chalk from 'chalk';
 2→import type { ParsedLine } from '../core/types.ts';
 3→import type { Formatter } from './formatter.interface.ts';
 4→import { getToolCategory, type ToolCategory } from '../utils/format-tool.ts';
 5→
 6→/**
 7→ * 格式化可讀輸出
 8→ */
 9→export class PrettyFormatter implements Formatter {
10→  format(parsed: ParsedLine): string {
11→    const time = this.formatTime(parsed.timestamp);
12→    const content = parsed.formatted;
13→
14→    // 來源標籤（多檔案監控時用於區分來源）
15→    const sourceLabel = parsed.sourceLabel
16→      ? chalk.cyan(parsed.sourceLabel.padEnd(10)) + ' '
17→      : '';
18→
19→    // function_call 類型使用 tool category 顏色
20→    if (parsed.type === 'function_call' && parsed.toolName) {
21→      const category = getToolCategory(parsed.toolName);
22→      const typeLabel = this.formatToolCategory(category);
23→      return `${chalk.gray(time)} ${sourceLabel}${typeLabel} ${content}`;
24→    }
25→
26→    const typeLabel = this.formatType(parsed.type);
27→    return `${chalk.gray(time)} ${sourceLabel}${typeLabel} ${content}`;
28→  }
29→
30→  /**
31→   * 根據 tool category 回傳對應顏色的標籤
32→   */
33→  private formatToolCategory(category: ToolCategory): string {
34→    switch (category) {
35→      case 'shell':
36→        return chalk.yellow('SHELL');
37→      case 'file':
38→        return chalk.green('FILE');
39→      case 'search':
40→        return chalk.cyan('SEARCH');
41→      case 'web':
42→        return chalk.blue('WEB');
43→      case 'task':
44→        return chalk.magenta('TASK');
45→      default:
46→        return chalk.redBright('FUNC');
47→    }
48→  }
49→
50→  private formatTime(timestamp: string): string {
51→    if (!timestamp) return '[--:--:--]';
52→
53→    try {
54→      const date = new Date(timestamp);
55→      const hours = date.getHours().toString().padStart(2, '0');
56→      const minutes = date.getMinutes().toString().padStart(2, '0');
57→      const seconds = date.getSeconds().toString().padStart(2, '0');
58→      return `[${hours}:${minutes}:${seconds}]`;
59→    } catch {
60→      return '[--:--:--]';
61→    }
62→  }
63→
64→  private formatType(type: string): string {
65→    switch (type) {
66→      case 'user':
67→        return chalk.green.bold('USER');
68→      case 'assistant':
69→      case 'gemini':
70→        // 統一 agent 回覆的顯示
71→        return chalk.blue.bold('ASST');
72→      case 'session_meta':
73→        return chalk.yellow('META');
74→      case 'function_call':
75→        return chalk.magenta('FUNC');
76→      case 'tool_result':
77→        return chalk.green('DONE');
78→      case 'custom-title':
79→        return chalk.cyan.bold('TITL');
80→      case 'output':
81→        return chalk.cyan('OUT ');
82→      case 'reasoning':
83→        return chalk.gray('THINK');
84→      default:
85→        return chalk.white(type.toUpperCase().slice(0, 4).padEnd(4));
86→    }
87→  }
88→}
