 6→/**
 7→ * tmux Terminal Controller
 8→ *
 9→ * 使用 Bun.spawn 直接調用 tmux CLI，零外部依賴。
10→ * Stateless 設計 — 不追蹤 pane 狀態，由 PaneManager 管理。
11→ */
12→export class TmuxController implements TerminalController {
13→  readonly name = 'tmux';
14→
15→  isAvailable(): boolean {
16→    return !!process.env.TMUX;
17→  }
18→
19→  async createPane(command: string, agentId: string): Promise<PaneInfo | null> {
20→    try {
21→      const proc = Bun.spawn(
22→        ['tmux', 'split-window', '-h', '-d', '-P', '-F', '#{pane_id}', command],
23→        { stdout: 'pipe', stderr: 'pipe' }
24→      );
25→
26→      const output = await new Response(proc.stdout).text();
27→      const exitCode = await proc.exited;
28→
29→      if (exitCode !== 0) {
30→        return null;
31→      }
32→
33→      const paneId = output.trim();
34→      if (!paneId) return null;
35→
36→      return { id: paneId, agentId };
37→    } catch {
38→      // tmux 指令失敗（binary 不存在等情況）
39→      return null;
40→    }
41→  }
42→
43→  async closePane(paneId: string): Promise<void> {
44→    try {
45→      const proc = Bun.spawn(['tmux', 'kill-pane', '-t', paneId], {
46→        stdout: 'ignore',
47→        stderr: 'ignore',
48→      });
49→      await proc.exited;
50→    } catch {
51→      // 靜默忽略（pane 可能已經關閉）
52→    }
53→  }
54→
55→  /**
56→   * 重新命名 pane（tmux 2.6+ 支援 select-pane -T）
57→   * Best-effort 操作，失敗靜默忽略
58→   */
59→  async renamePane(paneId: string, title: string): Promise<void> {
60→    try {
61→      const proc = Bun.spawn(
62→        ['tmux', 'select-pane', '-t', paneId, '-T', title],
63→        { stdout: 'ignore', stderr: 'ignore' }
64→      );
65→      await proc.exited;
66→    } catch {
67→      // 靜默忽略（tmux 版本不支援或 pane 已關閉）
68→    }
69→  }
70→
71→  /**
72→   * 套用佈局（main-vertical：主左、subagent 堆右均分）
73→   * Best-effort 操作，失敗不影響 pane 建立
74→   */
75→  async applyLayout(
76→    type: 'main-vertical' | 'main-horizontal' | 'tiled' = 'main-vertical'
77→  ): Promise<void> {
78→    try {
79→      const proc = Bun.spawn(['tmux', 'select-layout', type], {
80→        stdout: 'ignore',
81→        stderr: 'ignore',
82→      });
83→      await proc.exited;
84→    } catch {
85→      // 靜默忽略佈局失敗（best-effort）
86→    }
87→  }
88→}
