111→    agentTypeArg !== 'cursor'
112→  ) {
113→    console.error(
114→      'Error: --all option is only available for "claude", "codex", and "cursor" agent types.'
115→    );
116→    process.exit(1);
117→  }
118→
119→  // 展開 --all preset（只在選項未明確設定時才覆蓋）
120→  if (opts.all) {
121→    if (opts.verbose === undefined) opts.verbose = true;
122→    if (opts.withSubagents === undefined) opts.withSubagents = true;
123→    if (opts.autoSwitch === undefined) opts.autoSwitch = true;
124→  }
125→
126→  // 將 undefined 轉換為 false（對於非 preset 選項）
127→  const finalVerbose = opts.verbose ?? false;
128→  const finalInteractive = opts.interactive ?? false;
129→  let finalWithSubagents = opts.withSubagents ?? false;
130→  const finalAutoSwitch = opts.autoSwitch ?? false;
131→  const finalPane = opts.pane ?? false;
132→
133→  // interactive 選項對 claude、codex、cursor 有效
134→  if (
135→    finalInteractive &&
136→    agentTypeArg !== 'claude' &&
137→    agentTypeArg !== 'codex' &&
138→    agentTypeArg !== 'cursor'
139→  ) {
140→    console.error(
141→      'Error: --interactive option is only available for "claude", "codex", and "cursor" agent types.'
142→    );
143→    process.exit(1);
144→  }
145→
146→  // interactive 和 subagent 互斥
147→  if (finalInteractive && opts.subagent !== undefined) {
148→    console.error(
149→      'Error: --interactive and --subagent options cannot be used together.'
150→    );
151→    process.exit(1);
152→  }
153→
154→  // interactive 需要 follow 模式
155→  if (finalInteractive && !opts.follow) {
156→    console.error(
157→      'Error: --interactive requires --follow mode (cannot use with --no-follow).'
158→    );
159→    process.exit(1);
160→  }
161→
162→  // pane 選項對 claude、codex、cursor 有效
163→  if (
164→    finalPane &&
165→    agentTypeArg !== 'claude' &&
166→    agentTypeArg !== 'codex' &&
167→    agentTypeArg !== 'cursor'
168→  ) {
169→    console.error(
170→      'Error: --pane option is only available for "claude", "codex", and "cursor" agent types.'
171→    );
172→    process.exit(1);
173→  }
174→
175→  // pane 和 interactive 互斥
176→  if (finalPane && finalInteractive) {
177→    console.error(
178→      'Error: --pane and --interactive options cannot be used together.'
179→    );
180→    process.exit(1);
181→  }
182→
183→  // pane 和 subagent 互斥（pane 在多檔案監控模式，subagent 在單檔案模式）
184→  if (finalPane && opts.subagent !== undefined) {
185→    console.error(
186→      'Error: --pane and --subagent options cannot be used together.'
187→    );
188→    process.exit(1);
189→  }
190→
191→  // pane 需要 follow 模式
192→  if (finalPane && !opts.follow) {
193→    console.error(
194→      'Error: --pane requires --follow mode (cannot use with --no-follow).'
195→    );
196→    process.exit(1);
197→  }
198→
199→  // pane 自動啟用 withSubagents（subagent 偵測必須啟用才能開 pane）
200→  if (finalPane && !finalWithSubagents) {
201→    finalWithSubagents = true;
202→  }
203→
204→  // withSubagents 選項對 claude、codex、cursor 有效
205→  if (
206→    finalWithSubagents &&
207→    agentTypeArg !== 'claude' &&
208→    agentTypeArg !== 'codex' &&
209→    agentTypeArg !== 'cursor'
210→  ) {
211→    console.error(
212→      'Error: --with-subagents option is only available for "claude", "codex", and "cursor" agent types.'
213→    );
214→    process.exit(1);
215→  }
216→
217→  // sleepInterval 驗證
218→  if (
219→    opts.sleepInterval !== undefined &&
220→    (opts.sleepInterval < 100 || opts.sleepInterval > 60000)
221→  ) {
222→    console.error(
223→      'Error: --sleep-interval must be between 100 and 60000 milliseconds.'
224→    );
225→    process.exit(1);
226→  }
227→
228→  // lines 驗證
229→  if (opts.lines !== undefined && Number.isNaN(opts.lines)) {
230→    console.error('Error: --lines must be a valid number.');
231→    process.exit(1);
232→  }
233→
234→  return {
235→    agentType: agentTypeArg as AgentType,
236→    raw: opts.raw,
237→    project: opts.project,
238→    follow: opts.follow,
239→    verbose: finalVerbose,
240→    quiet: opts.quiet ?? false,
241→    sleepInterval: opts.sleepInterval ?? 500,
242→    lines: opts.lines,
243→    subagent: opts.subagent,
244→    interactive: finalInteractive,
245→    withSubagents: finalWithSubagents,
246→    autoSwitch: finalAutoSwitch,
247→    pane: finalPane,
248→    sessionId: sessionIdArg,
249→  };
250→}
