452→/**
453→ * Gemini CLI Agent
454→ */
455→export class GeminiAgent implements Agent {
456→  readonly type = 'gemini' as const;
457→  readonly finder: SessionFinder;
458→  readonly parser: LineParser;
459→
460→  constructor(options: ParserOptions = { verbose: false }) {
461→    this.finder = new GeminiSessionFinder();
