600→ * 時間排序輸出（用於 --no-follow --with-subagents 模式）
601→ * 收集所有檔案的行，按時間戳排序後輸出
602→ */
603→async function outputTimeSorted(
604→  files: WatchedFile[],
605→  parsers: Map<string, LineParser>,
606→  formatter: Formatter,
607→  _options: CliOptions
608→): Promise<void> {
609→  // 收集所有已解析的行
610→  const allParsedLines: Array<{
611→    parsed: import('./core/types.ts').ParsedLine;
612→    timestamp: Date;
613→  }> = [];
614→
615→  for (const file of files) {
616→    const parser = parsers.get(file.label);
617→    if (!parser) continue;
618→
619→    // 讀取檔案內容
620→    const bunFile = Bun.file(file.path);
621→    if (!(await bunFile.exists())) continue;
622→
623→    const content = await bunFile.text();
624→    const lines = content.split('\n').filter((line) => line.trim());
625→
626→    for (const line of lines) {
627→      let parsed = parser.parse(line);
628→      while (parsed) {
629→        parsed.sourceLabel = file.label;
630→        allParsedLines.push({
631→          parsed,
632→          timestamp: new Date(parsed.timestamp),
633→        });
634→        parsed = parser.parse(line);
635→      }
636→    }
637→  }
638→
639→  // 按時間戳排序（舊到新）
640→  allParsedLines.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
641→
642→  // 依序輸出
643→  for (const { parsed } of allParsedLines) {
644→    console.log(formatter.format(parsed));
645→  }
646→}
