651→function createInteractiveSessionManager(
652→  displayController: DisplayController
653→): SessionManager {
654→  const manager = new SessionManager({
655→    bufferSize: 1000,
656→    onOutput: (content: string, _session: WatcherSession) => {
657→      displayController.write(content);
658→    },
659→    onSessionAdded: (session: WatcherSession) => {
660→      displayController.write(
661→        chalk.yellow(`New session added: ${session.label}`)
662→      );
663→      displayController.updateStatusLine(
664→        manager.getAllSessions(),
665→        manager.getActiveIndex()
666→      );
667→    },
668→    onSessionSwitched: (
669→      session: WatcherSession,
670→      allSessions: WatcherSession[]
671→    ) => {
672→      const historyContent = session.buffer.slice();
673→      displayController.updateStatusLine(allSessions, manager.getActiveIndex());
674→      displayController.showSwitchMessage(session, historyContent);
675→    },
676→  });
677→  return manager;
678→}
