1969→async function startSingleWatch(
1970→  agent: Agent,
1971→  sessionFile: SessionFile,
1972→  formatter: Formatter,
1973→  options: CliOptions
1974→): Promise<void> {
1975→  log(options.quiet, chalk.gray('---'));
1976→
1977→  // 取得專案資訊（用於 auto-switch）
1978→  const projectInfo =
1979→    options.autoSwitch && agent.finder.getProjectInfo
1980→      ? await agent.finder.getProjectInfo(sessionFile.path)
1981→      : null;
1982→
1983→  let currentPath = sessionFile.path;
1984→  let watcher = new FileWatcher();
1985→
1986→  // 為 Gemini 準備可重建的 parser（避免狀態殘留）
1987→  // Codex parser 是無狀態的，不需要重建
1988→  let currentParser = agent.parser;
1989→
1990→  // 建立 onLine handler 函數（單一 agent 用，與 Claude 多檔案的 createOnLineHandler 不同）
1991→  const makeSingleLineHandler =
1992→    (parser: LineParser) =>
1993→    (line: string): void => {
1994→      if (options.agentType === 'gemini') {
1995→        // Gemini 模式：parser 有狀態追蹤，每次只回傳一個部分
1996→        // 需要反覆呼叫直到沒有更多內容
1997→        let parsed = parser.parse(line);
1998→        while (parsed) {
1999→          console.log(formatter.format(parsed));
2000→          parsed = parser.parse(line);
2001→        }
2002→      } else {
2003→        // Codex JSONL 模式：每行一個事件，單次處理
2004→        const parsed = parser.parse(line);
2005→        if (parsed) {
2006→          console.log(formatter.format(parsed));
2007→        }
2008→      }
2009→    };
2010→
2011→  // 切換到新 session 的函數
2012→  const switchToSession = async (nextFile: SessionFile): Promise<void> => {
2013→    watcher.stop();
2014→    currentPath = nextFile.path;
2015→
2016→    log(
2017→      options.quiet,
2018→      chalk.gray(`--- Switched to ${basename(nextFile.path)} ---`)
2019→    );
2020→
2021→    // Gemini 需要重建 parser 以清除狀態（processedMessageIds 等）
2022→    if (options.agentType === 'gemini') {
2023→      const newAgent = new GeminiAgent({ verbose: options.verbose });
2024→      currentParser = newAgent.parser;
2025→    }
2026→
2027→    watcher = new FileWatcher();
2028→    await watcher.start(nextFile.path, {
2029→      follow: true,
2030→      pollInterval: options.sleepInterval,
2031→      initialLines: options.lines,
2032→      jsonMode: options.agentType === 'gemini',
2033→      onLine: makeSingleLineHandler(currentParser),
2034→      onError: (error) => {
2035→        console.error(chalk.red(`Error: ${error.message}`));
2036→      },
2037→    });
2038→  };
2039→
2040→  // 建立 super-follow 控制器（如果支援）
2041→  const superFollow =
2042→    options.autoSwitch && projectInfo && agent.finder.findLatestInProject
2043→      ? createSuperFollowController({
2044→          projectDir: projectInfo.projectDir,
2045→          getCurrentPath: () => currentPath,
2046→          onSwitch: switchToSession,
2047→          autoSwitch: true,
2048→          findLatestInProject: agent.finder.findLatestInProject.bind(
2049→            agent.finder
2050→          ),
2051→        })
2052→      : null;
2053→
2054→  // 處理中斷信號
2055→  process.on('SIGINT', () => {
2056→    log(options.quiet, chalk.gray('\nStopping...'));
2057→    superFollow?.stop();
2058→    watcher.stop();
2059→    process.exit(0);
2060→  });
2061→
2062→  // 開始監控
2063→  await watcher.start(sessionFile.path, {
2064→    follow: options.follow,
2065→    pollInterval: options.sleepInterval,
2066→    initialLines: options.lines,
2067→    // Gemini 使用完整 JSON 檔案格式，需要啟用 jsonMode
2068→    jsonMode: options.agentType === 'gemini',
2069→    onLine: makeSingleLineHandler(currentParser),
2070→    onError: (error) => {
2071→      console.error(chalk.red(`Error: ${error.message}`));
2072→    },
2073→  });
2074→
2075→  // 如果不是 follow 模式，結束程式
2076→  if (!options.follow) {
2077→    process.exit(0);
2078→  }
2079→
2080→  // 啟動 super-follow（如果啟用）
2081→  superFollow?.start();
2082→
2083→  // 保持程式運行
2084→  log(options.quiet, chalk.gray('Watching for changes... (Ctrl+C to stop)'));
2085→}
2086→
2087→main().catch((error) => {
2088→  console.error(chalk.red(`Fatal error: ${error.message}`));
2089→  process.exit(1);
2090→});
