260→  /**
261→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
262→   * @param projectDir - workspace 目錄路徑
263→   */
264→  async findLatestInProject(projectDir: string): Promise<SessionFile | null> {
265→    const transcriptsDir = join(projectDir, 'agent-transcripts');
266→    // glob */*.jsonl 只匹配一層深度，不會匹配 subagents/ 下的檔案
267→    const glob = new Glob('*/*.jsonl');
268→    let latest: { path: string; mtime: Date } | null = null;
269→
270→    for await (const file of glob.scan({
271→      cwd: transcriptsDir,
272→      absolute: true,
273→    })) {
274→      try {
275→        const stats = await stat(file);
276→        if (!latest || stats.mtime > latest.mtime) {
277→          latest = { path: file, mtime: stats.mtime };
278→        }
279→      } catch {
280→        // 忽略
281→      }
282→    }
283→
284→    if (!latest) return null;
285→
286→    return {
287→      path: latest.path,
288→      mtime: latest.mtime,
289→      agentType: 'cursor',
290→    };
291→  }
292→
293→  /**
294→   * 從 session 路徑提取 workspace 目錄
295→   * 路徑格式: ~/.cursor/projects/{slug}/agent-transcripts/{UUID}/{UUID}.jsonl
296→   * 回傳: ~/.cursor/projects/{slug}
297→   */
298→  private _extractWorkspaceDir(sessionPath: string): string | null {
299→    const agentTranscriptsIdx = sessionPath.indexOf('/agent-transcripts/');
300→    if (agentTranscriptsIdx === -1) return null;
301→    return sessionPath.slice(0, agentTranscriptsIdx);
302→  }
303→
304→  /**
305→   * 讀取 .workspace-trusted 檔案中的 workspacePath
306→   */
307→  private async _readWorkspacePath(
308→    workspaceDir: string
309→  ): Promise<string | null> {
310→    try {
311→      const content = await readFile(
312→        join(workspaceDir, '.workspace-trusted'),
313→        'utf-8'
314→      );
