354→/**
355→ * 從文字中去除 <user_query> 包裝標籤
356→ */
357→function stripUserQueryTags(text: string): string {
358→  return text
359→    .replace(/^<user_query>\s*/s, '')
360→    .replace(/\s*<\/user_query>\s*$/s, '')
361→    .trim();
362→}
