364→/**
365→ * 從文字中去除 <attached_files> 區塊
366→ */
367→function stripAttachedFilesTags(text: string): string {
368→  return text.replace(/<attached_files>[\s\S]*?<\/attached_files>/g, '').trim();
369→}
