371→/**
372→ * Cursor JSONL 解析器（無狀態）
373→ * 格式: {"role":"user|assistant","message":{"content":[{"type":"text","text":"..."}]}}
374→ */
375→class CursorLineParser implements LineParser {
376→  private verbose: boolean;
377→
378→  constructor(options: ParserOptions = { verbose: false }) {
379→    this.verbose = options.verbose;
380→  }
381→
382→  parse(line: string): ParsedLine | null {
383→    if (!line.trim()) return null;
384→
385→    try {
386→      const data = JSON.parse(line);
387→      const role = data.role as string;
388→      if (!role) return null;
389→
390→      const content = data.message?.content;
391→      let text = contentToString(content);
392→
393→      if (!text.trim()) return null;
394→
395→      // 清除包裝標籤（先移除 attached_files 區塊，再移除 user_query 標籤）
396→      // 順序重要：attached_files 可能在 user_query 之前，必須先清除才能讓 user_query 的 ^ 錨點匹配
397→      if (role === 'user') {
398→        text = stripAttachedFilesTags(text);
399→        text = stripUserQueryTags(text);
400→      }
401→
402→      if (!text.trim()) return null;
403→
404→      const preview = truncateByLines(text, { verbose: this.verbose });
405→
406→      return {
407→        type: role, // 'user' | 'assistant' — PrettyFormatter 已支援
408→        timestamp: '', // Cursor 日誌無時間戳
409→        raw: data,
410→        formatted: formatMultiline(preview),
411→      };
412→    } catch {
413→      return null;
414→    }
415→  }
416→}
