 48→    // 初始讀取現有內容（直接呼叫，不需排程）
 49→    await this.readAndProcess(filePath, options.onLine);
 50→    await this.updateMtime(filePath);
 51→
 52→    // 如果需要持續監控
 53→    if (options.follow) {
 54→      this.isWatching = true;
 55→      this.startWatcher();
 56→      this.startPolling();
 57→    }
 58→  }
 59→
 60→  /**
 61→   * 排程讀取操作（防止競態條件）
 62→   * 如果正在處理，設為 pending 並返回
 63→   * 處理完成後如果 pending 為 true，再執行一次
 64→   */
 65→  private async scheduleRead(): Promise<void> {
 66→    if (!this.filePath || !this.options) return;
 67→
 68→    if (this.isProcessing) {
 69→      this.pendingRead = true;
 70→      return;
 71→    }
 72→
 73→    this.isProcessing = true;
 74→    this.pendingRead = false;
 75→
 76→    try {
 77→      await this.readAndProcess(this.filePath, this.options.onLine);
 78→      await this.updateMtime(this.filePath);
 79→
 80→      // 處理完成後，如果有 pending 請求，再執行一次
 81→      if (this.pendingRead) {
 82→        this.pendingRead = false;
 83→        await this.scheduleRead();
 84→      }
 85→    } catch (error) {
 86→      this.options.onError?.(error as Error);
 87→    } finally {
 88→      this.isProcessing = false;
 89→    }
 90→  }
