 1→import { Glob } from 'bun';
 2→import { stat } from 'node:fs/promises';
 3→import { basename, dirname, join } from 'node:path';
 4→import { makeAgentLabel } from '../core/detector-interfaces.ts';
 5→
 6→/** Cursor subagent ID 驗證：UUID 格式 */
 7→const UUID_REGEX =
 8→  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
 9→
10→/**
11→ * 從 session 檔案路徑推導 subagents 目錄
12→ * Cursor 路徑: {parentDir}/{UUID}/{UUID}.jsonl
13→ * subagents 位於: {parentDir}/{UUID}/subagents/
14→ */
15→export function getCursorSubagentsDir(sessionPath: string): string {
16→  return join(dirname(sessionPath), 'subagents');
17→}
18→
19→/**
20→ * 建立 Cursor subagent 檔案路徑（無 agent- 前綴，與 Claude 不同）
21→ */
22→export function buildCursorSubagentPath(
23→  subagentsDir: string,
24→  agentId: string
25→): string {
26→  return join(subagentsDir, `${agentId}.jsonl`);
27→}
28→
29→/**
30→ * 驗證 Cursor subagent ID 格式（UUID）
31→ */
32→export function isValidCursorSubagentId(id: string): boolean {
33→  return UUID_REGEX.test(id);
34→}
35→
36→/**
37→ * 建立 Cursor subagent 標籤（使用 UUID 前 8 字元）
38→ */
39→export function makeCursorAgentLabel(agentId: string): string {
40→  return makeAgentLabel(agentId.slice(0, 8));
41→}
42→
43→/**
44→ * 掃描 subagents 目錄，找出尚未被監控的新 subagent 檔案
45→ */
46→export async function scanCursorSubagents(
47→  subagentsDir: string,
48→  knownAgentIds: Set<string>
49→): Promise<string[]> {
50→  const newAgentIds: string[] = [];
51→
52→  try {
53→    const glob = new Glob('*.jsonl');
54→    for await (const file of glob.scan({ cwd: subagentsDir })) {
55→      const agentId = basename(file, '.jsonl');
56→      if (isValidCursorSubagentId(agentId) && !knownAgentIds.has(agentId)) {
57→        newAgentIds.push(agentId);
58→      }
59→    }
60→  } catch {
61→    // subagents 目錄不存在或無法存取時靜默忽略
62→  }
63→
64→  return newAgentIds;
65→}
66→
67→/**
68→ * 建立 subagent 檔案列表（含 stat 資訊），按 mtime 排序（舊到新）
69→ */
70→export async function buildCursorSubagentFiles(
71→  subagentsDir: string,
72→  agentIds: string[]
73→): Promise<Array<{ agentId: string; path: string; mtime: Date }>> {
74→  const statPromises = agentIds.map(async (agentId) => {
75→    const filePath = buildCursorSubagentPath(subagentsDir, agentId);
76→    try {
77→      const stats = await stat(filePath);
78→      return { agentId, path: filePath, mtime: stats.mtime };
79→    } catch {
80→      return null;
81→    }
82→  });
83→
84→  const results = (await Promise.all(statPromises)).filter(
85→    (r): r is NonNullable<typeof r> => r !== null
86→  );
87→  results.sort((a, b) => a.mtime.getTime() - b.mtime.getTime());
88→  return results;
89→}
