 6→/**
 7→ * 模擬 while loop 收集所有 parsed lines
 8→ * 如果超過 maxIterations 表示有無限迴圈
 9→ */
10→function collectAllParsedLines(
11→  parser: LineParser,
12→  line: string,
13→  maxIterations = 100
14→): ParsedLine[] {
15→  const results: ParsedLine[] = [];
16→  let parsed = parser.parse(line);
17→  let iterations = 0;
18→
19→  while (parsed && iterations < maxIterations) {
20→    results.push(parsed);
21→    parsed = parser.parse(line);
22→    iterations++;
23→  }
24→
25→  if (iterations >= maxIterations) {
26→    throw new Error('Infinite loop detected');
27→  }
28→  return results;
29→}
