366→/**
367→ * Claude Code JSONL 解析器
368→ */
369→class ClaudeLineParser implements LineParser {
370→  private verbose: boolean;
371→  /** 追蹤 assistant message 內部的處理進度 */
372→  private currentMessageState: {
373→    data: Record<string, unknown>;
374→    contentParts: Array<{
375→      type: string;
376→      text?: string;
377→      name?: string;
378→      input?: Record<string, unknown>;
379→    }>;
380→    partIndex: number;
381→    modelShort: string;
382→    hasTextBefore: boolean;
383→  } | null = null;
384→  /** 追蹤已處理的 line，避免 while 迴圈重複處理 */
385→  private lastProcessedLine: string | null = null;
386→
387→  constructor(options: ParserOptions = { verbose: false }) {
388→    this.verbose = options.verbose;
389→  }
390→
391→  parse(line: string): ParsedLine | null {
392→    // 如果正在處理 assistant message 的內部狀態
393→    if (this.currentMessageState) {
394→      const result = this.processAssistantPart();
395→      if (result) return result;
396→      // 處理完畢，清除狀態並回傳 null
397→      this.currentMessageState = null;
398→      return null;
399→    }
400→
401→    if (!line.trim()) return null;
402→
403→    // 避免重複處理同一個 line（非 assistant message 不需要 while 迴圈）
404→    if (line === this.lastProcessedLine) {
405→      return null;
406→    }
407→    this.lastProcessedLine = line;
408→
409→    try {
410→      const data = JSON.parse(line);
411→      const type = data.type || 'unknown';
412→      const timestamp = data.timestamp || '';
413→
414→      // custom-title event（Claude /rename command）
415→      if (type === CUSTOM_TITLE_TYPE) {
416→        const customTitle = data.customTitle as string;
417→        if (!customTitle) return null;
418→        return {
419→          type: CUSTOM_TITLE_TYPE,
420→          timestamp,
421→          raw: data,
422→          formatted: `Session renamed: "${customTitle}"`,
423→          isCustomTitle: true,
424→          customTitleValue: customTitle,
425→        };
426→      }
427→
428→      // assistant message 需要特殊處理（可能包含多個 tool_use）
429→      if (type === 'assistant') {
430→        return this.parseAssistantMessage(data, timestamp);
431→      }
432→
433→      // toolUseResult 記錄（subagent 完成時的回傳）
434→      if (data.toolUseResult) {
435→        return this.parseToolUseResult(data, timestamp);
436→      }
437→
438→      const formatted = this.format(data);
439→
440→      // 空內容不輸出
441→      if (!formatted) return null;
442→
443→      return {
444→        type,
445→        timestamp,
446→        raw: data,
447→        formatted,
448→      };
449→    } catch {
450→      return null;
451→    }
452→  }
453→
454→  /**
455→   * 解析 assistant message，拆分成多個部分
456→   */
457→  private parseAssistantMessage(
458→    data: Record<string, unknown>,
459→    _timestamp: string
460→  ): ParsedLine | null {
461→    const message = data.message as {
462→      model?: string;
463→      content: Array<{
464→        type: string;
465→        text?: string;
466→        name?: string;
467→        input?: Record<string, unknown>;
468→      }>;
469→    };
470→    const model = message?.model || '';
471→    const content = message?.content || [];
472→
473→    // 簡化 model 顯示
474→    const modelShort = model
475→      .replace('claude-', '')
476→      .replace('-20251101', '')
477→      .replace('-', ' ');
478→
479→    // 過濾有效的部分（text 或 tool_use）
480→    const validParts = content.filter(
481→      (part) =>
482→        (part.type === 'text' && part.text?.trim()) ||
483→        (part.type === 'tool_use' && part.name)
484→    );
485→
486→    if (validParts.length === 0) return null;
487→
488→    // 初始化狀態
489→    this.currentMessageState = {
490→      data,
491→      contentParts: validParts,
492→      partIndex: 0,
493→      modelShort,
494→      hasTextBefore: false,
495→    };
496→
497→    return this.processAssistantPart();
498→  }
499→
500→  /**
501→   * 處理 assistant message 的下一個部分
502→   */
503→  private processAssistantPart(): ParsedLine | null {
504→    if (!this.currentMessageState) return null;
505→
506→    const { data, contentParts, partIndex, modelShort, hasTextBefore } =
507→      this.currentMessageState;
508→    if (partIndex >= contentParts.length) return null;
509→
510→    const part = contentParts[partIndex];
511→    if (!part) return null;
512→
513→    this.currentMessageState.partIndex++;
514→    const timestamp = (data as { timestamp?: string }).timestamp || '';
515→
516→    if (part.type === 'text' && part.text) {
517→      this.currentMessageState.hasTextBefore = true;
518→      const preview = truncateByLines(part.text, { verbose: this.verbose });
519→      const modelInfo = modelShort && !hasTextBefore ? `(${modelShort})` : '';
520→      return {
521→        type: 'assistant',
522→        timestamp,
523→        raw: data,
524→        formatted: `${modelInfo}${formatMultiline(preview)}`,
525→      };
526→    }
527→
528→    if (part.type === 'tool_use' && part.name) {
529→      const isTask = isSubagentTool(part.name);
530→      const taskDescription =
531→        isTask && typeof part.input?.description === 'string'
532→          ? part.input.description
533→          : undefined;
534→
535→      return {
536→        type: 'function_call',
537→        timestamp,
538→        raw: part,
539→        formatted: formatToolUse(part.name, part.input, {
540→          verbose: this.verbose,
541→        }),
542→        toolName: part.name,
543→        isTaskToolUse: isTask,
544→        taskDescription,
545→      };
546→    }
547→
548→    return null;
549→  }
550→
551→  /**
552→   * 解析 toolUseResult 記錄（subagent 完成時的回傳）
553→   */
554→  private parseToolUseResult(
555→    data: Record<string, unknown>,
556→    timestamp: string
557→  ): ParsedLine | null {
558→    const toolUseResult = data.toolUseResult as {
559→      status?: string;
560→      agentId?: string;
561→      prompt?: string;
562→      totalDurationMs?: number;
563→      totalTokens?: number;
564→      totalToolUseCount?: number;
565→    };
566→
567→    if (!toolUseResult) return null;
568→
569→    const { status, agentId, totalDurationMs, totalTokens, totalToolUseCount } =
570→      toolUseResult;
571→
572→    // 格式化輸出
573→    const parts: string[] = [];
574→    if (status) parts.push(status);
575→    if (agentId) parts.push(`agent:${agentId}`);
576→    if (totalDurationMs) parts.push(`${(totalDurationMs / 1000).toFixed(1)}s`);
577→    if (totalTokens) parts.push(`${totalTokens} tokens`);
578→    if (totalToolUseCount) parts.push(`${totalToolUseCount} tools`);
579→
580→    const formatted = parts.length > 0 ? `(${parts.join(', ')})` : '';
581→
582→    return {
583→      type: 'tool_result',
584→      timestamp,
585→      raw: data,
586→      formatted,
587→    };
588→  }
589→
590→  private format(data: Record<string, unknown>): string {
591→    const type = data.type as string;
592→
593→    switch (type) {
594→      case 'file-history-snapshot': {
595→        return ''; // 不顯示 snapshot
596→      }
597→
598→      case 'user': {
599→        const message = data.message as { content: unknown };
600→        const content = contentToString(message?.content);
601→        const preview = truncateByLines(content, { verbose: this.verbose });
602→        return formatMultiline(preview);
603→      }
604→
605→      // assistant 由 parseAssistantMessage 處理
606→
607→      default:
608→        return '';
609→    }
610→  }
611→}
