 15→/**
 16→ * Gemini CLI Session Finder
 17→ * 目錄結構: ~/.gemini/tmp/<project_hash>/chats/session-*.json
 18→ */
 19→class GeminiSessionFinder implements SessionFinder {
 20→  private baseDir: string;
 21→
 22→  constructor() {
 23→    this.baseDir = join(homedir(), '.gemini', 'tmp');
 24→  }
 25→
 26→  getBaseDir(): string {
 27→    return this.baseDir;
 28→  }
 29→
 30→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 31→    const glob = new Glob('*/chats/session-*.json');
 32→    const files: { path: string; mtime: Date }[] = [];
 33→
 34→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 35→      // 如果有 project filter，做模糊比對（對路徑）
 36→      if (options.project) {
 37→        const pattern = options.project.toLowerCase();
 38→        if (!file.toLowerCase().includes(pattern)) continue;
 39→      }
 40→
 41→      try {
 42→        const stats = await stat(file);
 43→        files.push({ path: file, mtime: stats.mtime });
 44→      } catch {
 45→        // 忽略無法讀取的檔案
 46→      }
 47→    }
 48→
 49→    if (files.length === 0) return null;
 50→
 51→    // 按修改時間排序，取最新的
 52→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 53→
 54→    const latest = files[0];
 55→    if (!latest) return null;
 56→
 57→    return {
 58→      path: latest.path,
 59→      mtime: latest.mtime,
 60→      agentType: 'gemini',
 61→    };
 62→  }
 63→
 64→  /**
 65→   * 依 session ID 查找 session 檔案
 66→   * 檔名格式：session-{timestamp}-{8位UUID}.json
 67→   * 支援匹配：8位 UUID 前綴、完整 UUID（需讀取 JSON）、時間戳
 68→   */
 69→  async findBySessionId(
 70→    sessionId: string,
 71→    options: { project?: string }
 72→  ): Promise<SessionFile | null> {
 73→    const glob = new Glob('*/chats/session-*.json');
 74→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
 75→    // 用於完整 UUID 匹配的候選（需要讀取 JSON）
 76→    const uuidCandidates: { path: string; mtime: Date }[] = [];
 77→
 78→    // 檔名格式：session-{timestamp}-{8位UUID}.json
 79→    // 例如：session-2025-12-28T10-10-3f3fa388.json
 80→    const filenamePattern = /^session-(.+)-([0-9a-f]{8})\.json$/i;
 81→    // 完整 UUID 格式
 82→    const fullUuidPattern =
 83→      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
 84→
 85→    const searchTerm = sessionId.toLowerCase();
 86→    const isFullUuid = fullUuidPattern.test(sessionId);
 87→
 88→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
 89→      // project filter
 90→      if (options.project) {
 91→        const pattern = options.project.toLowerCase();
 92→        if (!file.toLowerCase().includes(pattern)) continue;
 93→      }
 94→
 95→      const filename = file.split('/').pop() || '';
 96→      const match = filename.match(filenamePattern);
 97→
 98→      if (!match) continue;
 99→
100→      const timestampPart = match[1] || '';
101→      const shortUuid = (match[2] || '').toLowerCase();
102→
103→      // 計算匹配優先級
104→      let priority = 0;
105→
106→      // 1. 對 8 位 UUID 前綴進行匹配
107→      if (shortUuid === searchTerm) {
108→        priority = 6; // 精確匹配
109→      } else if (shortUuid.startsWith(searchTerm)) {
110→        priority = 5; // 前綴匹配
111→      } else if (shortUuid.includes(searchTerm)) {
112→        priority = 4; // 包含匹配
113→      }
114→
115→      // 2. 對時間戳進行匹配（如果 UUID 沒有匹配到）
116→      if (priority === 0 && timestampPart) {
117→        const normalizedTimestamp = timestampPart.toLowerCase();
118→        if (normalizedTimestamp === searchTerm) {
119→          priority = 3; // 精確匹配時間戳
120→        } else if (normalizedTimestamp.startsWith(searchTerm)) {
121→          priority = 2; // 前綴匹配時間戳
122→        } else if (normalizedTimestamp.includes(searchTerm)) {
123→          priority = 1; // 包含匹配時間戳
124→        }
125→      }
126→
127→      // 如果是完整 UUID 且沒有匹配到檔名，加入候選列表等待讀取 JSON
128→      if (priority === 0 && isFullUuid) {
129→        try {
130→          const stats = await stat(file);
131→          uuidCandidates.push({ path: file, mtime: stats.mtime });
132→        } catch {
133→          // 忽略
134→        }
135→        continue;
136→      }
137→
138→      if (priority === 0) continue;
139→
140→      try {
141→        const stats = await stat(file);
142→        candidates.push({ path: file, mtime: stats.mtime, priority });
143→      } catch {
144→        // 忽略無法讀取的檔案
145→      }
146→    }
147→
148→    // 如果有檔名匹配的候選，直接使用
149→    if (candidates.length > 0) {
150→      candidates.sort((a, b) => {
151→        if (b.priority !== a.priority) return b.priority - a.priority;
152→        return b.mtime.getTime() - a.mtime.getTime();
153→      });
154→
155→      const best = candidates[0];
156→      if (!best) return null;
157→
158→      return {
159→        path: best.path,
160→        mtime: best.mtime,
161→        agentType: 'gemini',
162→      };
163→    }
164→
165→    // 如果是完整 UUID 且沒有檔名匹配，嘗試讀取 JSON 內容
166→    if (isFullUuid && uuidCandidates.length > 0) {
167→      for (const candidate of uuidCandidates) {
168→        try {
169→          const content = await Bun.file(candidate.path).text();
170→          const data = JSON.parse(content);
171→          if (data.sessionId && data.sessionId.toLowerCase() === searchTerm) {
172→            return {
173→              path: candidate.path,
174→              mtime: candidate.mtime,
175→              agentType: 'gemini',
176→            };
177→          }
178→        } catch {
179→          // 忽略解析錯誤
180→        }
181→      }
182→    }
183→
184→    return null;
185→  }
