  1→import { readFile, stat } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { basename, dirname, join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ParsedLine,
  8→  ParserOptions,
  9→  ProjectInfo,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import {
 13→  contentToString,
 14→  truncateByLines,
 15→  formatMultiline,
 16→} from '../../utils/text.ts';
 17→import { isValidCursorSubagentId } from '../../cursor/watch-builder.ts';
