 19→/**
 20→ * Cursor Session Finder
 21→ * 目錄結構: ~/.cursor/projects/{workspace-slug}/agent-transcripts/{UUID}/{UUID}.jsonl
 22→ * Subagent: {UUID}/subagents/{subagent-UUID}.jsonl
 23→ */
 24→class CursorSessionFinder implements SessionFinder {
 25→  private _baseDir: string;
 26→
 27→  constructor() {
 28→    this._baseDir = join(homedir(), '.cursor', 'projects');
 29→  }
 30→
 31→  getBaseDir(): string {
 32→    return this._baseDir;
 33→  }
 34→
 35→  /**
 36→   * 設定 baseDir（用於測試）
 37→   */
 38→  setBaseDir(dir: string): void {
 39→    this._baseDir = dir;
 40→  }
 41→
 42→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 43→    const glob = new Glob('*/agent-transcripts/*/*.jsonl');
 44→    let latest: { path: string; mtime: Date } | null = null;
 45→
 46→    // Cache .workspace-trusted lookups per workspace slug
 47→    const workspacePathCache = new Map<string, string | null>();
 48→
 49→    for await (const file of glob.scan({
 50→      cwd: this._baseDir,
 51→      absolute: true,
 52→    })) {
 53→      // 排除 subagent 檔案
 54→      if (file.includes('/subagents/')) continue;
 55→
 56→      // Project filter
 57→      if (options.project) {
 58→        const matched = await this._matchProject(
 59→          file,
 60→          options.project,
 61→          workspacePathCache
 62→        );
 63→        if (!matched) continue;
 64→      }
 65→
 66→      try {
 67→        const stats = await stat(file);
 68→        if (!latest || stats.mtime > latest.mtime) {
 69→          latest = { path: file, mtime: stats.mtime };
 70→        }
 71→      } catch {
 72→        // 忽略無法讀取的檔案
 73→      }
 74→    }
 75→
 76→    if (!latest) return null;
 77→
 78→    return {
 79→      path: latest.path,
 80→      mtime: latest.mtime,
 81→      agentType: 'cursor',
 82→    };
 83→  }
 84→
 85→  /**
 86→   * 依 session ID 查找 session 檔案
 87→   * Cursor session ID 為 UUID v4
 88→   * 支援部分匹配：精確 > 前綴 > 包含
 89→   */
 90→  async findBySessionId(
 91→    sessionId: string,
 92→    options: { project?: string }
 93→  ): Promise<SessionFile | null> {
 94→    const glob = new Glob('*/agent-transcripts/*/*.jsonl');
 95→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
 96→    const searchTerm = sessionId.toLowerCase();
 97→
 98→    const workspacePathCache = new Map<string, string | null>();
 99→
100→    for await (const file of glob.scan({
101→      cwd: this._baseDir,
102→      absolute: true,
103→    })) {
104→      if (file.includes('/subagents/')) continue;
105→
106→      if (options.project) {
107→        const matched = await this._matchProject(
108→          file,
109→          options.project,
110→          workspacePathCache
111→        );
112→        if (!matched) continue;
113→      }
114→
115→      // 從路徑提取 UUID（目錄名即為 session ID）
116→      const sessionDir = basename(dirname(file));
117→      const normalizedId = sessionDir.toLowerCase();
118→
119→      let priority = 0;
120→      if (normalizedId === searchTerm) {
121→        // UUID 唯一，精確匹配直接返回
122→        try {
123→          const stats = await stat(file);
124→          return { path: file, mtime: stats.mtime, agentType: 'cursor' };
125→        } catch {
126→          continue;
127→        }
128→      } else if (normalizedId.startsWith(searchTerm)) {
129→        priority = 2; // 前綴匹配
130→      } else if (normalizedId.includes(searchTerm)) {
131→        priority = 1; // 包含匹配
132→      }
133→
134→      if (priority === 0) continue;
135→
136→      try {
137→        const stats = await stat(file);
138→        candidates.push({ path: file, mtime: stats.mtime, priority });
139→      } catch {
140→        // 忽略無法讀取的檔案
141→      }
142→    }
143→
144→    if (candidates.length === 0) return null;
145→
146→    candidates.sort((a, b) => {
147→      if (b.priority !== a.priority) return b.priority - a.priority;
148→      return b.mtime.getTime() - a.mtime.getTime();
149→    });
150→
151→    const best = candidates[0];
152→    if (!best) return null;
153→
154→    return {
155→      path: best.path,
156→      mtime: best.mtime,
157→      agentType: 'cursor',
158→    };
159→  }
160→
161→  /**
162→   * 查找 subagent session 檔案
163→   * 掃描 workspace/agent-transcripts/UUID/subagents/UUID.jsonl
164→   * @param options.subagentId - 部分 UUID 匹配
165→   */
166→  async findSubagent(options: {
167→    project?: string;
168→    subagentId?: string;
169→  }): Promise<SessionFile | null> {
170→    const glob = new Glob('*/agent-transcripts/*/subagents/*.jsonl');
171→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
172→    const searchTerm = options.subagentId?.toLowerCase();
173→
174→    const workspacePathCache = new Map<string, string | null>();
175→
176→    for await (const file of glob.scan({
177→      cwd: this._baseDir,
178→      absolute: true,
179→    })) {
180→      // 從檔名提取 UUID
181→      const filename = basename(file, '.jsonl');
182→      if (!isValidCursorSubagentId(filename)) continue;
183→
184→      // Project filter
185→      if (options.project) {
186→        const matched = await this._matchProject(
187→          file,
188→          options.project,
189→          workspacePathCache
190→        );
191→        if (!matched) continue;
192→      }
193→
194→      // Subagent ID 匹配
195→      const normalizedId = filename.toLowerCase();
196→      let priority = 3; // 無 filter 時預設優先
197→
198→      if (searchTerm) {
199→        if (normalizedId === searchTerm) {
200→          // 精確匹配直接返回
201→          try {
202→            const stats = await stat(file);
203→            return { path: file, mtime: stats.mtime, agentType: 'cursor' };
204→          } catch {
205→            continue;
206→          }
207→        } else if (normalizedId.startsWith(searchTerm)) {
208→          priority = 2; // 前綴匹配
209→        } else if (normalizedId.includes(searchTerm)) {
210→          priority = 1; // 包含匹配
211→        } else {
212→          continue;
213→        }
214→      }
215→
216→      try {
217→        const stats = await stat(file);
218→        candidates.push({ path: file, mtime: stats.mtime, priority });
219→      } catch {
220→        // 忽略
221→      }
222→    }
223→
224→    if (candidates.length === 0) return null;
225→
226→    // 按優先度排序，相同優先度按 mtime 排序（最新在前）
227→    candidates.sort((a, b) => {
228→      if (b.priority !== a.priority) return b.priority - a.priority;
229→      return b.mtime.getTime() - a.mtime.getTime();
230→    });
231→
232→    const best = candidates[0];
233→    if (!best) return null;
234→
235→    return {
236→      path: best.path,
237→      mtime: best.mtime,
238→      agentType: 'cursor',
239→    };
240→  }
241→
242→  /**
243→   * 從 session 檔案取得專案資訊（用於 auto-switch）
244→   * 提取 workspace 目錄作為 projectDir
245→   */
246→  async getProjectInfo(sessionPath: string): Promise<ProjectInfo | null> {
247→    const workspaceDir = this._extractWorkspaceDir(sessionPath);
248→    if (!workspaceDir) return null;
249→
250→    const slug = basename(workspaceDir);
251→    const workspacePath = await this._readWorkspacePath(workspaceDir);
252→    const displayName = workspacePath ? basename(workspacePath) : slug;
253→
254→    return {
255→      projectDir: workspaceDir,
256→      displayName,
257→    };
258→  }
259→
260→  /**
261→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
262→   * @param projectDir - workspace 目錄路徑
263→   */
264→  async findLatestInProject(projectDir: string): Promise<SessionFile | null> {
265→    const transcriptsDir = join(projectDir, 'agent-transcripts');
266→    // glob */*.jsonl 只匹配一層深度，不會匹配 subagents/ 下的檔案
267→    const glob = new Glob('*/*.jsonl');
268→    let latest: { path: string; mtime: Date } | null = null;
269→
270→    for await (const file of glob.scan({
271→      cwd: transcriptsDir,
272→      absolute: true,
273→    })) {
274→      try {
275→        const stats = await stat(file);
276→        if (!latest || stats.mtime > latest.mtime) {
277→          latest = { path: file, mtime: stats.mtime };
278→        }
279→      } catch {
280→        // 忽略
281→      }
282→    }
283→
284→    if (!latest) return null;
285→
286→    return {
287→      path: latest.path,
288→      mtime: latest.mtime,
289→      agentType: 'cursor',
290→    };
291→  }
292→
293→  /**
294→   * 從 session 路徑提取 workspace 目錄
295→   * 路徑格式: ~/.cursor/projects/{slug}/agent-transcripts/{UUID}/{UUID}.jsonl
296→   * 回傳: ~/.cursor/projects/{slug}
297→   */
298→  private _extractWorkspaceDir(sessionPath: string): string | null {
299→    const agentTranscriptsIdx = sessionPath.indexOf('/agent-transcripts/');
300→    if (agentTranscriptsIdx === -1) return null;
301→    return sessionPath.slice(0, agentTranscriptsIdx);
302→  }
303→
304→  /**
305→   * 讀取 .workspace-trusted 檔案中的 workspacePath
306→   */
307→  private async _readWorkspacePath(
308→    workspaceDir: string
309→  ): Promise<string | null> {
310→    try {
311→      const content = await readFile(
312→        join(workspaceDir, '.workspace-trusted'),
313→        'utf-8'
314→      );
315→      const data = JSON.parse(content);
316→      return data.workspacePath || null;
317→    } catch {
318→      return null;
319→    }
320→  }
321→
322→  /**
323→   * 專案模糊匹配
324→   * 匹配 workspace slug 或 .workspace-trusted 的 workspacePath
325→   */
326→  private async _matchProject(
327→    filePath: string,
328→    project: string,
329→    cache: Map<string, string | null>
330→  ): Promise<boolean> {
331→    const pattern = project.toLowerCase();
332→
333→    // 對完整路徑做模糊比對（包含 slug）
334→    if (filePath.toLowerCase().includes(pattern)) return true;
335→
336→    // 嘗試 .workspace-trusted 的 workspacePath
337→    const workspaceDir = this._extractWorkspaceDir(filePath);
338→    if (!workspaceDir) return false;
339→
340→    const slug = basename(workspaceDir);
341→    if (!cache.has(slug)) {
342→      cache.set(slug, await this._readWorkspacePath(workspaceDir));
343→    }
344→
345→    const workspacePath = cache.get(slug);
346→    if (workspacePath && workspacePath.toLowerCase().includes(pattern)) {
347→      return true;
348→    }
349→
350→    return false;
351→  }
352→}
