354→/**
355→ * 從文字中去除 <user_query> 包裝標籤
356→ */
357→function stripUserQueryTags(text: string): string {
358→  return text
359→    .replace(/^<user_query>\s*/s, '')
360→    .replace(/\s*<\/user_query>\s*$/s, '')
361→    .trim();
362→}
363→
364→/**
365→ * 從文字中去除 <attached_files> 區塊
366→ */
367→function stripAttachedFilesTags(text: string): string {
368→  return text.replace(/<attached_files>[\s\S]*?<\/attached_files>/g, '').trim();
369→}
