  7→/**
  8→ * 快取中的 session 記錄
  9→ */
 10→interface CachedSession {
 11→  path: string;
 12→  mtime: number; // timestamp
 13→  cwd: string;
 14→}
 15→
 16→/**
 17→ * 快取檔案格式
 18→ */
 19→interface CacheFile {
 20→  version: number;
 21→  lastScanTime: number;
 22→  sessions: CachedSession[];
 23→}
 24→
 25→/** session_meta 的 payload 結構 */
 26→interface SessionMetaPayload {
 27→  cwd?: string;
 28→  source?: unknown;
 29→}
 30→
 31→/**
 32→ * 讀取 Codex JSONL 首行的 session_meta
 33→ * 回傳 cwd（主 session）或 null（非 session_meta、subagent、或讀取失敗）
 34→ */
 35→export async function readMainSessionMeta(
 36→  filePath: string
 37→): Promise<{ cwd: string } | null> {
 38→  try {
 39→    const content = await Bun.file(filePath).text();
 40→    const firstLine = content.split('\n')[0];
 41→    if (!firstLine) return null;
 42→
 43→    const meta = JSON.parse(firstLine);
 44→    if (meta.type !== 'session_meta') return null;
 45→
 46→    const payload = meta.payload as SessionMetaPayload | undefined;
 47→    if (!payload?.cwd) return null;
 48→
 49→    // 排除 subagent（source 為物件且含 subagent 屬性）
 50→    const source = payload.source;
 51→    if (typeof source === 'object' && source !== null && 'subagent' in source) {
 52→      return null;
 53→    }
 54→
 55→    return { cwd: payload.cwd };
 56→  } catch {
 57→    return null;
 58→  }
 59→}
