 61→const CACHE_VERSION = 2;
 62→const CACHE_FILE_NAME = '.agent-tail-cache.json';
 63→
 64→/** 快取刷新間隔（毫秒）- 用於偵測新的 session */
 65→const CACHE_REFRESH_INTERVAL_MS = 2000;
 66→
 67→/**
 68→ * Codex Session 快取
 69→ * - 啟動時掃描所有 session，建立 cwd → sessions 的索引
 70→ * - 持久化快取到 ~/.codex/.agent-tail-cache.json
 71→ * - 使用 mtime 判斷是否需要更新
 72→ */
 73→export class CodexSessionCache {
 74→  private baseDir: string;
 75→  private cacheFile: string;
 76→  private cache: Map<string, CachedSession[]> = new Map();
 77→  private initialized = false;
 78→  private initPromise: Promise<void> | null = null;
 79→  private lastRefreshTime = 0;
 80→
 81→  constructor(baseDir?: string) {
 82→    this.baseDir = baseDir ?? join(homedir(), '.codex', 'sessions');
 83→    this.cacheFile = join(dirname(this.baseDir), CACHE_FILE_NAME);
 84→  }
 85→
 86→  /**
 87→   * 初始化快取（懶加載）
 88→   */
 89→  async init(): Promise<void> {
 90→    if (this.initialized) return;
 91→
 92→    // 防止並發初始化
 93→    if (this.initPromise) {
 94→      return this.initPromise;
 95→    }
 96→
 97→    this.initPromise = this.doInit();
 98→    await this.initPromise;
 99→    this.initPromise = null;
100→  }
101→
102→  private async doInit(): Promise<void> {
103→    // 嘗試從磁碟載入快取
104→    const loaded = await this.loadFromDisk();
105→    if (loaded) {
106→      this.initialized = true;
107→      return;
108→    }
109→
110→    // 快取不存在或過期，重新掃描
111→    await this.scanAllSessions();
112→    await this.saveToDisk();
113→    this.initialized = true;
114→  }
115→
116→  /**
117→   * 從磁碟載入快取
118→   */
119→  private async loadFromDisk(): Promise<boolean> {
120→    try {
121→      const content = await readFile(this.cacheFile, 'utf-8');
122→      const data: CacheFile = JSON.parse(content);
123→
124→      if (data.version !== CACHE_VERSION) {
125→        return false;
126→      }
127→
128→      // 重建索引
129→      this.cache.clear();
130→      for (const session of data.sessions) {
131→        if (!this.cache.has(session.cwd)) {
132→          this.cache.set(session.cwd, []);
133→        }
134→        this.cache.get(session.cwd)!.push(session);
135→      }
136→
137→      // 每個 cwd 內按 mtime 排序（降序）
138→      for (const [, sessions] of this.cache) {
139→        sessions.sort((a, b) => b.mtime - a.mtime);
140→      }
141→
142→      return true;
143→    } catch {
144→      return false;
145→    }
146→  }
147→
148→  /**
149→   * 儲存快取到磁碟
150→   */
151→  private async saveToDisk(): Promise<void> {
152→    try {
153→      const sessions: CachedSession[] = [];
154→      for (const [, cwdSessions] of this.cache) {
155→        sessions.push(...cwdSessions);
156→      }
157→
158→      const data: CacheFile = {
159→        version: CACHE_VERSION,
160→        lastScanTime: Date.now(),
161→        sessions,
162→      };
163→
164→      // 確保目錄存在
165→      await mkdir(dirname(this.cacheFile), { recursive: true });
166→      await writeFile(this.cacheFile, JSON.stringify(data, null, 2));
167→    } catch {
168→      // 忽略寫入錯誤
169→    }
170→  }
171→
172→  /**
173→   * 掃描所有 session 檔案，建立索引
174→   */
175→  private async scanAllSessions(): Promise<void> {
176→    const glob = new Glob('**/*.jsonl');
177→    const sessions: CachedSession[] = [];
178→
179→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
180→      const filename = basename(file);
181→      if (!filename.startsWith('rollout-')) continue;
182→
183→      const meta = await readMainSessionMeta(file);
184→      if (meta) {
185→        try {
186→          const stats = await stat(file);
187→          sessions.push({
188→            path: file,
189→            mtime: stats.mtime.getTime(),
190→            cwd: meta.cwd,
191→          });
192→        } catch {
193→          // 忽略無法 stat 的檔案
194→        }
195→      }
196→    }
197→
198→    // 建立 cwd 索引
199→    this.cache.clear();
200→    for (const session of sessions) {
201→      if (!this.cache.has(session.cwd)) {
202→        this.cache.set(session.cwd, []);
203→      }
204→      this.cache.get(session.cwd)!.push(session);
205→    }
206→
207→    // 每個 cwd 內按 mtime 排序（降序）
208→    for (const [, cwdSessions] of this.cache) {
209→      cwdSessions.sort((a, b) => b.mtime - a.mtime);
210→    }
211→  }
212→
213→  /**
214→   * 取得指定 cwd 的最新 session
215→   * 會驗證檔案是否存在，若不存在則嘗試下一個
216→   * 定期刷新以偵測新的 session
217→   */
218→  async getLatestByCwd(cwd: string): Promise<SessionFile | null> {
219→    await this.init();
220→
221→    // 檢查是否需要刷新（增量更新）
222→    await this.maybeRefresh();
223→
224→    const sessions = this.cache.get(cwd);
225→    if (!sessions || sessions.length === 0) return null;
226→
227→    // 找到第一個存在且有效的 session
228→    for (const session of sessions) {
229→      // 驗證檔案是否存在
230→      const file = Bun.file(session.path);
231→      if (await file.exists()) {
232→        return {
233→          path: session.path,
234→          mtime: new Date(session.mtime),
235→          agentType: 'codex',
236→        };
237→      }
238→    }
239→
240→    return null;
241→  }
242→
243→  /**
244→   * 檢查是否需要刷新快取（根據時間間隔）
245→   * 如果需要，掃描最近的 session 進行增量更新
246→   */
247→  private async maybeRefresh(): Promise<void> {
248→    const now = Date.now();
249→    if (now - this.lastRefreshTime < CACHE_REFRESH_INTERVAL_MS) {
250→      return;
251→    }
252→
253→    this.lastRefreshTime = now;
254→
255→    // 增量刷新：只掃描今天的 session
256→    const today = new Date();
257→    const year = today.getFullYear().toString();
258→    const month = (today.getMonth() + 1).toString().padStart(2, '0');
259→    const day = today.getDate().toString().padStart(2, '0');
260→    const todayDir = join(this.baseDir, year, month, day);
261→
262→    // 檢查今天的目錄是否存在（使用 stat 而非 Bun.file）
263→    try {
264→      const dirStats = await stat(todayDir);
265→      if (!dirStats.isDirectory()) return;
266→    } catch {
267→      return;
268→    }
269→
270→    // 掃描今天的 session
271→    const glob = new Glob('rollout-*.jsonl');
272→    for await (const file of glob.scan({ cwd: todayDir, absolute: true })) {
273→      const filename = basename(file);
274→      if (!filename.startsWith('rollout-')) continue;
275→
276→      try {
277→        // 檢查是否已在快取中
278→        let alreadyCached = false;
279→        for (const [, sessions] of this.cache) {
280→          if (sessions.some((s) => s.path === file)) {
281→            alreadyCached = true;
282→            break;
283→          }
284→        }
285→        if (alreadyCached) continue;
286→
287→        const meta = await readMainSessionMeta(file);
288→        if (meta) {
289→          const stats = await stat(file);
290→          const newSession: CachedSession = {
291→            path: file,
292→            mtime: stats.mtime.getTime(),
293→            cwd: meta.cwd,
294→          };
295→
296→          if (!this.cache.has(newSession.cwd)) {
297→            this.cache.set(newSession.cwd, []);
298→          }
299→          this.cache.get(newSession.cwd)!.push(newSession);
300→
301→          // 重新排序該 cwd 的 sessions（降序）
302→          this.cache.get(newSession.cwd)!.sort((a, b) => b.mtime - a.mtime);
303→        }
304→      } catch {
305→        // 忽略無法解析的檔案
306→      }
307→    }
308→  }
309→
310→  /**
311→   * 列出所有已知專案
312→   */
313→  async getAllProjects(): Promise<string[]> {
314→    await this.init();
315→    return Array.from(this.cache.keys());
316→  }
317→
318→  /**
319→   * 清除快取（用於測試或強制刷新）
320→   */
321→  clear(): void {
322→    this.cache.clear();
323→    this.initialized = false;
324→  }
325→}
