12→/**
13→ * 模擬 while loop 收集所有 parsed lines
14→ * 如果超過 maxIterations 表示有無限迴圈
15→ */
16→function collectAllParsedLines(
17→  parser: LineParser,
18→  line: string,
19→  maxIterations = 100
20→): ParsedLine[] {
21→  const results: ParsedLine[] = [];
22→  let parsed = parser.parse(line);
23→  let iterations = 0;
24→
25→  while (parsed && iterations < maxIterations) {
26→    results.push(parsed);
27→    parsed = parser.parse(line);
28→    iterations++;
29→  }
30→
31→  if (iterations >= maxIterations) {
32→    throw new Error('Infinite loop detected');
33→  }
34→  return results;
35→}
