    }) as typeof process.exit;

    const consoleSpy = spyOn(console, 'error').mockImplementation(() => {});

    expect(() =>
      parseArgs(['node', 'agent-tail', 'gemini', '--subagent'])
    ).toThrow('process.exit called');
    expect(exitCode).toBe(1);

    consoleSpy.mockRestore();
