    if (ago > 0) {
      const mtime = new Date(Date.now() - ago);
      await utimes(filePath, mtime, mtime);
    }
    return filePath;
  }

  test('returns empty array for empty directory', async () => {
    const result = await finder.listSessions!({});
    expect(result).toEqual([]);
  });

