import { Chalk } from 'chalk';
import type { AgentType } from '../core/types.ts';
import type { SessionListItem } from '../core/types.ts';

// Force color output regardless of TTY detection
const chalkForced = new Chalk({ level: 3 });

/**
 * Format a Date as relative time string (e.g., "3m ago", "1h ago")
 */
export function formatRelativeTime(date: Date): string {
  const diffMs = Date.now() - date.getTime();
  if (diffMs < 1000) return 'just now';

  const diffSec = Math.floor(diffMs / 1000);
  if (diffSec < 60) return `${diffSec}s ago`;

  const diffMin = Math.floor(diffSec / 60);
  if (diffMin < 60) return `${diffMin}m ago`;

  const diffHour = Math.floor(diffMin / 60);
  if (diffHour < 24) return `${diffHour}h ago`;

  const diffDay = Math.floor(diffHour / 24);
  return `${diffDay}d ago`;
}

const AGENT_COLORS: Record<AgentType, (s: string) => string> = {
  claude: (s) => chalkForced.magenta(s),
  codex: (s) => chalkForced.green(s),
  gemini: (s) => chalkForced.blue(s),
  cursor: (s) => chalkForced.yellow(s),
};

/**
 * Format a list of sessions as tab-separated lines
 */
export function formatSessionList(
  items: SessionListItem[],
  options: { color: boolean }
): string[] {
  return items.map((item) => {
    const agentStr = options.color
      ? (AGENT_COLORS[item.agentType] ?? ((s: string) => s))(item.agentType)
      : item.agentType;

    return [
      item.shortId,
      formatRelativeTime(item.mtime),
      agentStr,
      item.project ?? '',
    ].join('\t');
  });
}

