 7→/**
 8→ * Format a Date as relative time string (e.g., "3m ago", "1h ago")
 9→ */
10→export function formatRelativeTime(date: Date): string {
11→  const diffMs = Date.now() - date.getTime();
12→  if (diffMs < 1000) return 'just now';
13→
14→  const diffSec = Math.floor(diffMs / 1000);
15→  if (diffSec < 60) return `${diffSec}s ago`;
16→
17→  const diffMin = Math.floor(diffSec / 60);
18→  if (diffMin < 60) return `${diffMin}m ago`;
19→
20→  const diffHour = Math.floor(diffMin / 60);
21→  if (diffHour < 24) return `${diffHour}h ago`;
22→
23→  const diffDay = Math.floor(diffHour / 24);
24→  return `${diffDay}d ago`;
25→}
