 73→export function parseArgs(args: string[]): CliOptions {
 74→  const program = createProgram();
 75→  program.parse(args);
 76→
 77→  const agentTypeArg = program.args[0];
 78→  const sessionIdArg = program.args[1];
 79→  const opts = program.opts();
 80→
 81→  // 驗證 agent 類型
 82→  if (
 83→    agentTypeArg !== 'codex' &&
 84→    agentTypeArg !== 'claude' &&
 85→    agentTypeArg !== 'gemini' &&
 86→    agentTypeArg !== 'cursor'
 87→  ) {
 88→    console.error(
 89→      `Error: Invalid agent type "${agentTypeArg}". Use "codex", "claude", "gemini", or "cursor".`
 90→    );
 91→    process.exit(1);
 92→  }
 93→
 94→  // --list 互斥驗證（最廣泛的排除，放在最前面）
 95→  const finalList = opts.list ?? false;
 96→  if (finalList) {
 97→    if (opts.interactive) {
 98→      console.error(
 99→        'Error: --list and --interactive options cannot be used together.'
100→      );
101→      process.exit(1);
102→    }
103→    if (opts.subagent !== undefined) {
104→      console.error(
105→        'Error: --list and --subagent options cannot be used together.'
106→      );
107→      process.exit(1);
108→    }
109→    if (opts.raw) {
110→      console.error('Error: --list and --raw options cannot be used together.');
111→      process.exit(1);
112→    }
113→    if (opts.all) {
114→      console.error('Error: --list and --all options cannot be used together.');
115→      process.exit(1);
116→    }
117→    if (sessionIdArg !== undefined) {
118→      console.error('Error: --list cannot be used with a session ID argument.');
119→      process.exit(1);
120→    }
121→    if (opts.pane) {
122→      console.error(
123→        'Error: --list and --pane options cannot be used together.'
124→      );
125→      process.exit(1);
126→    }
127→    if (opts.withSubagents) {
128→      console.error(
129→        'Error: --list and --with-subagents options cannot be used together.'
130→      );
131→      process.exit(1);
132→    }
133→    if (opts.autoSwitch) {
134→      console.error(
135→        'Error: --list and --auto-switch options cannot be used together.'
136→      );
137→      process.exit(1);
138→    }
139→  }
140→
141→  // subagent 選項對 claude、codex、cursor 有效
142→  if (
143→    opts.subagent !== undefined &&
144→    agentTypeArg !== 'claude' &&
145→    agentTypeArg !== 'codex' &&
146→    agentTypeArg !== 'cursor'
147→  ) {
148→    console.error(
149→      'Error: --subagent option is only available for "claude", "codex", and "cursor" agent types.'
150→    );
151→    process.exit(1);
152→  }
153→
154→  // --all preset 選項對 claude、codex、cursor 有效（需要在展開前驗證）
155→  if (
156→    opts.all &&
157→    agentTypeArg !== 'claude' &&
158→    agentTypeArg !== 'codex' &&
159→    agentTypeArg !== 'cursor'
160→  ) {
161→    console.error(
162→      'Error: --all option is only available for "claude", "codex", and "cursor" agent types.'
163→    );
164→    process.exit(1);
165→  }
166→
167→  // 展開 --all preset（只在選項未明確設定時才覆蓋）
168→  if (opts.all) {
169→    if (opts.verbose === undefined) opts.verbose = true;
170→    if (opts.withSubagents === undefined) opts.withSubagents = true;
171→    if (opts.autoSwitch === undefined) opts.autoSwitch = true;
172→  }
173→
174→  // 將 undefined 轉換為 false（對於非 preset 選項）
175→  let finalFollow = opts.follow;
176→  if (finalList) finalFollow = false;
177→  const finalVerbose = opts.verbose ?? false;
178→  const finalInteractive = opts.interactive ?? false;
179→  let finalWithSubagents = opts.withSubagents ?? false;
180→  const finalAutoSwitch = opts.autoSwitch ?? false;
181→  const finalPane = opts.pane ?? false;
182→
183→  // interactive 選項對 claude、codex、cursor 有效
184→  if (
185→    finalInteractive &&
186→    agentTypeArg !== 'claude' &&
187→    agentTypeArg !== 'codex' &&
188→    agentTypeArg !== 'cursor'
189→  ) {
190→    console.error(
191→      'Error: --interactive option is only available for "claude", "codex", and "cursor" agent types.'
192→    );
193→    process.exit(1);
194→  }
195→
196→  // interactive 和 subagent 互斥
197→  if (finalInteractive && opts.subagent !== undefined) {
198→    console.error(
199→      'Error: --interactive and --subagent options cannot be used together.'
200→    );
201→    process.exit(1);
202→  }
203→
204→  // interactive 需要 follow 模式
205→  if (finalInteractive && !opts.follow) {
206→    console.error(
207→      'Error: --interactive requires --follow mode (cannot use with --no-follow).'
208→    );
209→    process.exit(1);
210→  }
211→
212→  // pane 選項對 claude、codex、cursor 有效
213→  if (
214→    finalPane &&
215→    agentTypeArg !== 'claude' &&
216→    agentTypeArg !== 'codex' &&
