218→  ) {
219→    console.error(
220→      'Error: --pane option is only available for "claude", "codex", and "cursor" agent types.'
221→    );
222→    process.exit(1);
223→  }
224→
225→  // pane 和 interactive 互斥
226→  if (finalPane && finalInteractive) {
227→    console.error(
228→      'Error: --pane and --interactive options cannot be used together.'
229→    );
230→    process.exit(1);
