237→    );
238→    process.exit(1);
239→  }
240→
241→  // pane 需要 follow 模式
242→  if (finalPane && !opts.follow) {
243→    console.error(
244→      'Error: --pane requires --follow mode (cannot use with --no-follow).'
245→    );
246→    process.exit(1);
247→  }
248→
249→  // pane 自動啟用 withSubagents（subagent 偵測必須啟用才能開 pane）
250→  if (finalPane && !finalWithSubagents) {
251→    finalWithSubagents = true;
252→  }
253→
254→  // withSubagents 選項對 claude、codex、cursor 有效
255→  if (
256→    finalWithSubagents &&
257→    agentTypeArg !== 'claude' &&
258→    agentTypeArg !== 'codex' &&
259→    agentTypeArg !== 'cursor'
260→  ) {
261→    console.error(
262→      'Error: --with-subagents option is only available for "claude", "codex", and "cursor" agent types.'
263→    );
264→    process.exit(1);
265→  }
266→
267→  // sleepInterval 驗證
268→  if (
269→    opts.sleepInterval !== undefined &&
