273→      'Error: --sleep-interval must be between 100 and 60000 milliseconds.'
274→    );
275→    process.exit(1);
276→  }
277→
278→  // lines 驗證
279→  if (opts.lines !== undefined && Number.isNaN(opts.lines)) {
280→    console.error('Error: --lines must be a valid number.');
