290→    quiet: opts.quiet ?? false,
291→    sleepInterval: opts.sleepInterval ?? 500,
292→    lines: opts.lines,
293→    subagent: opts.subagent,
294→    interactive: finalInteractive,
295→    withSubagents: finalWithSubagents,
296→    autoSwitch: finalAutoSwitch,
297→    pane: finalPane,
298→    sessionId: sessionIdArg,
299→    list: finalList,
300→  };
